item.fsiRule:
        var codes = [
    "SI10001000": 0,
    "SI10002000": 0
];

for (code : codes){
    var item = companyValuesByCodeAndCompanyName(code.first, companyName);
    codes[code.first] = item;
}

var result = 0.0;

if (codes["SI10002000"] != 0){
    var ratio = (codes["SI10001000"] * 1.0) / (codes["SI10002000"] * 1.0);
    result = ratio;
} else {
    result = 0;
}

return result;

item.consolidationRule:

var items = companyValuesByCode("SI10009000");
var total_sum = 0.0;
var total_count = 0;

for (entry : items) {
    var values = entry.second;
    total_sum = total_sum + sum(values);
    total_count = total_count + size(values);
}

print("consolidate SI10009000:");
print(total_count);

if (total_count == 0) { return 0.0; }
return total_sum / total_count * 1.0;

